import{_ as t,o as a,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"58. Meal Intervals And Rest Intervals","description":"","frontmatter":{"title":"58. Meal Intervals And Rest Intervals","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","shift-work","breaks","preliminary"]},"headers":[],"relativePath":"ebas/mspp/hours-of-work/58-meal-intervals-and-rest-intervals.md","filePath":"ebas/mspp/hours-of-work/58-meal-intervals-and-rest-intervals.md"}'),s={name:"ebas/mspp/hours-of-work/58-meal-intervals-and-rest-intervals.md"};function o(i,e,l,d,h,m){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_58-meal-intervals-and-rest-intervals" tabindex="-1">58. Meal Intervals And Rest Intervals <a class="header-anchor" href="#_58-meal-intervals-and-rest-intervals" aria-label="Permalink to &quot;58. Meal Intervals And Rest Intervals&quot;">​</a></h1><p><strong>58.1</strong> Meal Intervals - All Employees</p><p><strong>a.</strong> An Employee will be entitled to an unpaid meal interval of not less than 30 minutes and not more than 60 minutes during each shift.</p><p><strong>b.</strong> An Employee will be entitled to an unpaid meal interval of not less than 30 minutes and not more than 60 minutes during each shift save that:</p><p><strong>(i)</strong> the meal interval for pharmacists shall be not less than 45 minutes and not more than 60 minutes unless the pharmacist agrees to a meal break of not less than 30 minutes.</p><p><strong>c.</strong> Such meal interval will be designated in writing and shall not be counted as time worked.</p><p><strong>d.</strong> An Employee is entitled to meal breaks as provided by this clause and is entitled to be relieved from duty to enable them to take such breaks. For the purposes of this clause the term “duty” shall include the requirement to remain contactable by telephone, pager or mobile phone.</p><p><strong>e.</strong> Any Employee who is unable to be relieved of duty to enable them to take a meal break shall be paid for the break as time worked at the ordinary rate plus 50%.</p><p><strong>58.2</strong> Meal break not taken – escalation Each Employer will describe, in writing, the steps to be taken where an Employee does not take a scheduled meal break to ensure that:</p><p><strong>a.</strong> Wherever possible, the meal break is rescheduled and taken during the shift; and</p><p><strong>b.</strong> Consideration is given to what caused the Employee to miss the scheduled meal break and whether any additional action is required to address those causes and eliminate the likelihood of recurrence.</p><p><strong>58.3</strong> Night Shift Meal Interval Each Employee on night duty who is not relieved from duty (and “on call” during the rostered meal interval) shall be granted a paid meal interval of not less than 20 minutes to be commenced after completing three hours and not more than five hours of duty. Such time shall be counted as time worked.</p><p><strong>58.4</strong> Meetings and training</p><p><strong>a.</strong> Other than in exceptional circumstances, the Employer shall not require an Employee to attend staff meetings or mandatory training (including professional development training) or undertake other work requirements during the meals breaks specified in clause 58.1.</p><p><strong>b.</strong> Where due to exceptional circumstances an Employer requires an Employee to attend a meeting or training, or undertake work requirements during a meal break, the Employee shall be afforded another meal break of equal duration immediately before or after the meeting, or be paid their meal break i.e receive the additional payment for not being relieved of duty provided for in clause 58.1.</p><p><strong>58.5</strong> Rest Intervals At a time suitable to the Employer, two rest periods - each of ten minutes duration - shall be given to each Employee during each eight hour period of duty and shall be counted as time worked.</p><p>Plain language terms: meal break, lunch break, tea break.</p>',17)])])}const c=t(s,[["render",o]]);export{u as __pageData,c as default};
